Code Good:
// Migration with proper indexes:
Schema::create('orders', function (Blueprint $table) {
    $table->id();
    $table->foreignId('user_id')->index();
    $table->string('status')->index();
    $table->timestamp('created_at')->index();
    $table->index(['user_id', 'status']); // composite
});

// Check slow queries:
DB::listen(function ($query) {
    if ($query->time > 100) Log::warning('Slow query', ['sql' => $query->sql]);
});

Code Bad:
Schema::create('orders', function (Blueprint $table) {
    $table->id();
    $table->foreignId('user_id'); // no index
    $table->string('status'); // no index
    // Queries filtering by user_id or status will full-scan
});

Code Good:
// Chunked processing - fixed memory:
User::where('active', false)->chunk(1000, function ($users) {
    foreach ($users as $user) {
        $user->anonymize();
    }
});

// Cursor - one row at a time:
foreach (User::where('active', false)->cursor() as $user) {
    $user->delete();
}

// Lazy collection:
User::lazy()->each(function ($user) {
    // processes one at a time
});

Code Bad:
$users = User::all(); // Loads ALL rows into memory
foreach ($users as $user) {
    $user->process();
}
// Fatal: Allowed memory size exhausted

