// Standard pagination (with count):
$users = User::where('active', true)->paginate(20);

// Cursor pagination (no count, faster for large tables):
$users = User::where('active', true)->cursorPaginate(20);

// Simple pagination (no count, prev/next only):
$users = User::where('active', true)->simplePaginate(20);

# Nginx configuration:
gzip on;
gzip_types application/json text/plain application/xml;
gzip_min_length 256;
gzip_comp_level 5;
gzip_vary on;

# Or in PHP middleware (less efficient):
class CompressResponse {
    public function handle($request, Closure $next) {
        $response = $next($request);
        if (str_contains($request->header('Accept-Encoding', ''), 'gzip')) {
            // Let Nginx handle this instead
        }
        return $response;
    }
}
